 18→public class ReaderPostServiceStarter {
 19→    public static final String ARG_TAG = "tag";
 20→    public static final String ARG_ACTION = "action";
 21→    public static final String ARG_BLOG_ID = "blog_id";
 22→    public static final String ARG_FEED_ID = "feed_id";
 23→
 24→    public static final String ARG_TAG_PARAM_SLUG = "tag-slug";
 25→    public static final String ARG_TAG_PARAM_DISPLAY_NAME = "tag-display-name";
 26→    public static final String ARG_TAG_PARAM_TITLE = "tag-title";
 27→    public static final String ARG_TAG_PARAM_ENDPOINT = "tag-endpoint";
 28→    public static final String ARG_TAG_PARAM_TAGTYPE = "tag-type";
