 39→    public void performTask(Object companion, UpdateAction action,
 40→                            ReaderTag tag, long blogId, long feedId) {
 41→        mListenerCompanion = companion;
 42→
 43→        EventBus.getDefault().post(new ReaderEvents.UpdatePostsStarted(action, tag));
 44→
 45→        if (tag != null) {
 46→            updatePostsWithTag(tag, action);
 47→        } else if (blogId > -1) {
 48→            updatePostsInBlog(blogId, action);
 49→        } else if (feedId > -1) {
 50→            updatePostsInFeed(feedId, action);
 51→        }
 52→    }
