import kotlinx.coroutines.ExperimentalCoroutinesApi
import org.assertj.core.api.Assertions.assertThat
import org.junit.Before
import org.junit.Test
import org.mockito.Mock
import org.mockito.kotlin.any
import org.mockito.kotlin.whenever
import org.wordpress.android.BaseUnitTest
import org.wordpress.android.models.ReaderTagType
import org.wordpress.android.ui.reader.utils.ReaderUtilsWrapper

/**
 * Tests for [BloggingPromptsPostTagProvider] focusing on pagination fix.
 *
 * This test verifies that the ReaderTag returned by promptIdSearchReaderTag has the proper
 * endpoint set so that isTagTopic() returns true. This is critical for correct pagination
 * behavior in the Reader when viewing blogging prompt responses.
 *
 * Related issue: Regression in Prompts responses list pagination
 * - Posts were shifting places when loading due to incorrect sorting column selection
 * - Pagination was stopping prematurely
 * - Root cause: ReaderTag was created without an endpoint, causing isTagTopic() to return false
 */
@OptIn(ExperimentalCoroutinesApi::class)
class BloggingPromptsPostTagProviderPaginationTest : BaseUnitTest() {
    @Mock
    private lateinit var readerUtilsWrapper: ReaderUtilsWrapper

    private lateinit var tagProvider: BloggingPromptsPostTagProvider

    @Before
    fun setUp() {
        tagProvider = BloggingPromptsPostTagProvider(readerUtilsWrapper)
    }

    @Test
    fun `promptIdSearchReaderTag returns tag with endpoint containing read tags path`() {
        whenever(readerUtilsWrapper.getTagFromTagUrl(any())).thenReturn(BLOGGING_PROMPT_ID_TAG)

        val readerTag = tagProvider.promptIdSearchReaderTag("valid-url")

        assertThat(readerTag.endpoint).contains("/read/tags/")
    }

    @Test
    fun `promptIdSearchReaderTag returns tag where isTagTopic returns true`() {
        whenever(readerUtilsWrapper.getTagFromTagUrl(any())).thenReturn(BLOGGING_PROMPT_ID_TAG)

        val readerTag = tagProvider.promptIdSearchReaderTag("valid-url")

        assertThat(readerTag.isTagTopic).isTrue()
    }

    @Test
    fun `promptIdSearchReaderTag returns tag with correct tag type`() {
        whenever(readerUtilsWrapper.getTagFromTagUrl(any())).thenReturn(BLOGGING_PROMPT_ID_TAG)

        val readerTag = tagProvider.promptIdSearchReaderTag("valid-url")

        assertThat(readerTag.tagType).isEqualTo(ReaderTagType.FOLLOWED)
    }

    @Test
    fun `promptIdSearchReaderTag returns tag with correct tag slug`() {
        whenever(readerUtilsWrapper.getTagFromTagUrl(any())).thenReturn(BLOGGING_PROMPT_ID_TAG)

        val readerTag = tagProvider.promptIdSearchReaderTag("valid-url")

        assertThat(readerTag.tagSlug).isEqualTo(BLOGGING_PROMPT_ID_TAG)
    }

    @Test
    fun `promptIdSearchReaderTag returns tag with endpoint in correct format`() {
        whenever(readerUtilsWrapper.getTagFromTagUrl(any())).thenReturn(BLOGGING_PROMPT_ID_TAG)

        val readerTag = tagProvider.promptIdSearchReaderTag("valid-url")

        val expectedEndpoint = "read/tags/$BLOGGING_PROMPT_ID_TAG/posts"
        assertThat(readerTag.endpoint).isEqualTo(expectedEndpoint)
    }

    @Test
    fun `promptIdSearchReaderTag with fallback tag returns tag with proper endpoint`() {
        whenever(readerUtilsWrapper.getTagFromTagUrl(any())).thenReturn("")

        val readerTag = tagProvider.promptIdSearchReaderTag("invalid-url")

        assertThat(readerTag.isTagTopic).isTrue()
        assertThat(readerTag.tagSlug).isEqualTo(BloggingPromptsPostTagProvider.BLOGGING_PROMPT_TAG)
    }

    companion object {
        private const val BLOGGING_PROMPT_ID_TAG = "dailyprompt-1234"
    }
}
"}

